<template>
	<view class="history-box" v-if="keywordList.length">
		<view class="hd">
			<text class="title">搜索历史</text>
			<view class="icon-button" @click="clearHistory">
				<u-icon name="trash" />
			</view>
		</view>
		<view class="keyword-box">
			<view class="keyword-list">
				<view class="keyword-item" v-for="(item,index) in keywordList" :key="index"
					@click="itemClick(item,index)">
					{{item}}
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import {
		mapGetters,
		mapMutations
	} from 'vuex'
	import _ from 'lodash'

	export default {
		props: {
			keyword: {
				type: String,
				default: ''
			}
		},
		components: {

		},
		data() {
			return {

			}
		},
		computed: {
			...mapGetters({
				keywords: 'searchHistory/keywords'
			}),
			keywordList() {
				const re = _.filter(this.keywords, (e) => {
					if (_.startsWith(e, this.keyword))
						return e
				})

				return re.reverse()
			},
		},
		async mounted() {

		},
		methods: {
			...mapMutations({
				clearHistory: 'searchHistory/clearHistory'
			}),
			itemClick(item, index) {
				this.$emit('search', item)
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.history-box {
		background-color: #f4f4f5;
		padding: 20rpx;

		.hd {
			display: flex;
			justify-content: space-between;

			.icon-button {
				display: flex;
				align-items: center;
				justify-content: center;
			}
		}

		.keyword-box {
			margin-top: 20rpx;

			.keyword-list {
				display: flex;
				gap: 20rpx;
				flex-wrap: wrap;

				.keyword-item {
					background-color: #c8c9cc;
					min-width: 60rpx;
					text-align: center;
					padding: 10rpx 20rpx;
					border-radius: 10rpx;
				}
			}
		}
	}
</style>