<template>
	<view class="check-box">
		<view class="icon-box" :class="{'on':value===true}" @click="handelClick">
			<u-icon name="checkmark-circle" size="40"></u-icon>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			value: {
				type: Boolean,
				default: false
			},
		},
		data() {
			return {

			}
		},
		methods: {
			handelClick() {
				this.$emit('input', this.value ? false : true)
				this.$emit('change', this.value ? false : true)
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.check-box {
		.icon-box {
			width: 40rpx;
			height: 40rpx;
			overflow: hidden;
			display: flex;
			align-items: center;
			justify-content: center;
			// border: 1px solid #f4f4f5;
			color: #c8c9cc !important;
			padding: 10rpx;
		}

		.on {
			color: #F05C02 !important;
			// border-color: #F05C02;
		}
	}
</style>