<template>
	<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
		:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close">
		<view class="popup-title">搜索</view>
		<view class="block-height"></view>
		<view class="search">
			<u-search placeholder="搜索标题|编号|正文" v-model.trim="keyword" shape="square" :show-action="true"
				@search="doSearch" @custom="doSearch" @focus="handelFocus" />
		</view>
		<view class="popup-content">
			<template v-if="step == 1">
				<search-history :keyword="keyword" @search="historySearch" />
			</template>
			<template v-if="step == 2">
				<slot name="searchlist" :keyword="keyword">搜索列表</slot>
			</template>
		</view>
	</u-popup>
</template>

<script>
	import {
		mapMutations,
	} from 'vuex'
	import SearchHistory from './search-history'

	export default {
		components: {
			SearchHistory
		},
		props: {
			show: {
				type: Boolean,
				default: false
			},
			customStyle: {
				type: Object,
				default: () => {}
			}
		},
		data() {
			return {
				popupShow: false,

				keyword: '',
				step: 1,
			}
		},
		computed: {

		},
		watch: {
			show: {
				handler(nv) {
					this.popupShow = nv
				},
				immediate: true
			}
		},
		methods: {
			...mapMutations({
				addKeyWord: 'searchHistory/addKeyWord'
			}),
			close() {
				this.$emit('update:show', false)
			},
			doSearch() {
				if (this.keyword) {
					this.addKeyWord(this.keyword)
					this.step = 2
				}
			},
			historySearch(e) {
				this.keyword = e
				this.doSearch()
			},
			handelFocus() {
				this.step = 1
			},
		},
	}
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.block-height {
		height: 20rpx;
		background-color: #f4f4f5;
	}

	.search {
		padding: 20rpx;
		background-color: #fff;
	}

	.popup-content {
		height: calc(var(--vh) * 72);
		/* #ifndef H5 */
		height: calc(var(--vh) * 72 - calc(var(--status-bar-height) + 10px));
		/* #endif */
	}
</style>