<template>
	<view class="page">
		<u-navbar title="账号风控" :z-index="980" :custom-back="$util.back"></u-navbar>
		<search-bar :button-type="['filter','manage','add-button']" :is-manage.sync="isManage"
			@show-search-popup="showSearch=true" @show-filter-popup="showFilter=true" @show-edit-popup="handelAdd" />
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false" refresher-enabled="true"
			:refresher-triggered="triggered" :refresher-threshold="100" refresher-background="#fff"
			@refresherpulling="onPulling" @refresherrefresh="onRefresh" @refresherrestore="onRestore"
			@refresherabort="onAbort" @scrolltolower="lower">
			<RiskList :list="list" :isManage="isManage" @delete="handelDelete" @edit="handelEdit" />
			<u-loadmore v-show="list.length" :status="loading" icon-type="circle" @loadmore="fetchData"></u-loadmore>
		</scroll-view>
		<!-- 弹层组件 -->
		<search-popup :show.sync="showSearch">
			<template v-slot:searchlist="{keyword}">
				<risk-search :keyword="keyword" />
			</template>
		</search-popup>
		<my-popup :show.sync="showEdit" :title="editTitle">
			<risk-edit :source="editForm" @submit="handelSave" />
		</my-popup>
		<my-popup :show.sync="showFilter" title="筛选" :scrollHeight="600">
			<risk-filter :form-data="queryForm" @filter="doFilter" />
		</my-popup>
	</view>
</template>

<script>
	import _ from 'lodash'
	import RiskList from './components/risk-list'
	import RiskSearch from './components/risk-search'
	import RiskEdit from './components/risk-edit'
	import RiskFilter from './components/risk-filter'

	import SearchBar from '@/components/manage-search/search-bar'
	import SearchPopup from '@/components/manage-search/search-popup'
	import MyPopup from '@/components/manage-search/my-popup'


	export default {
		components: {
			RiskList,
			RiskSearch,
			RiskEdit,
			RiskFilter,

			SearchBar,
			SearchPopup,

			MyPopup,
		},
		data() {
			return {
				triggered: false,
				queryForm: {
					keyword: '',
					keyword_type: '',
					page: 1,
					limit: 10,
				},
				list: [],
				total: 0,
				loading: 'loadmore',
				isManage: false,

				showFilter: false,
				showSearch: false,
				showEdit: false,

				editForm: {},
			}
		},
		computed: {
			editTitle() {
				if (this.editForm.id)
					return '编辑'
				else
					return `添加`
			},
		},
		watch: {
			isManage(nv) {
				if (nv === true) {
					if (!this.list.length) {
						this.$util.msg('数据为空')
						this.isManage = false
					}
				}
			}
		},
		onReady() {

		},
		async onLoad() {
			this._freshing = false
			this.triggered = true
			await this.fetchData()
		},
		methods: {
			//----下拉刷新-end------
			onPulling(e) {
				console.log("onpulling")
			},
			onRefresh() {
				if (this._freshing) return
				this._freshing = true
				this.reloadData().then(() => {
					this.triggered = false
					this._freshing = false
				})
			},
			onRestore() {
				this.triggered = 'restore'; // 需要重置
				console.log("onRestore");
			},
			onAbort() {
				console.log("onAbort");
			},
			//----下拉刷新-start------
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
				} = await this.$u.api.riskList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				return this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 删除回调
			handelDelete(e) {
				this.list = e
			},
			// 筛选回调
			doFilter(e) {
				this.showFilter = false
				_.merge(this.queryForm, e)
				this.reloadData()
			},
			// 添加
			handelAdd() {
				this.editForm = {}
				this.showEdit = true
			},
			// 编辑
			handelEdit(e) {
				this.editForm = e
				this.showEdit = true
			},
			// 添加、编辑时保存
			async handelSave(e) {
				await this.$u.api.riskCreate(e)
				this.$util.msg('保存成功')
				this.showEdit = false
				this.reloadData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.page {
		.scroll_content {
			height: calc(var(--vh) * 100 - 96px - calc(var(--status-bar-height) + 10px));
		}
	}
</style>