<template>
	<view class="search-box">
		<view class="search">
			<u-search placeholder="搜索" disabled shape="square" :show-action="false" />
			<view class="search-mask" @click="searchClick"></view>
		</view>
		<view class="right-action">
			<view class="action-item" v-if="buttonType.includes('filter')" @click="filterClick">
				<text class="iconfont icon-guolv"></text>
				<text class="title">筛选</text>
			</view>
			<view class="action-item" v-if="buttonType.includes('manage')" @click="manageClick">
				<u-icon name="list-dot" size="26" />
				<text class="title" v-if="!isManage">管理</text>
				<text class="title" v-else>取消</text>
			</view>
			<view class="action-item" v-if="buttonType.includes('add-button')" @click="addClick">
				<u-icon name="plus" size="26" />
				<text class="title">新增</text>
			</view>
		</view>

	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			// 按钮类型
			buttonType: {
				type: Array,
				required: true,
				default: () => [],
				validator: function(value) {
					const arr = [
						'filter', 'manage', 'add-button'
					]
					let flag = true
					value.forEach(item => {
						if (!arr.includes(item))
							flag = false
					})
					return flag
				},
			},
			isManage: {
				type: Boolean,
				default: false,
			}
		},
		data() {
			return {

			}
		},
		computed: {

		},
		methods: {
			searchClick() {
				this.$emit('show-search-popup')
			},
			filterClick() {
				this.$emit('show-filter-popup')
			},
			manageClick() {
				this.$emit('update:isManage', !this.isManage)
			},
			addClick() {
				this.$emit('show-edit-popup')
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.search-box {
		display: flex;
		align-items: center;
		padding: 20rpx;
		gap: 20rpx;
		background-color: #fff;

		.search {
			flex: 1;
			position: relative;

			.search-mask {
				position: absolute;
				z-index: 2;
				top: 0;
				left: 0;
				width: 100%;
				height: 100%;
			}
		}

		.right-action {
			display: flex;
			flex-wrap: nowrap;
			align-items: center;
			gap: 10rpx;

			.action-item {
				cursor: pointer;
				border-radius: 10rpx;
				line-height: 1;
				padding: 12rpx 0;

				.iconfont {
					font-size: 26rpx;
				}

				.title {
					margin-left: 10rpx;
				}

				&:active {
					opacity: .8;
					background-color: #f4f4f5;
				}
			}

		}
	}
</style>