<template>
	<view>
		<view class="list-box">
			<template v-if="list.length">
				<view class="list-item" v-for="item,index in list" :key="index" @click="handelItemClick(item)">
					<view class="wrap">
						<icon-checkbox v-show="isManage" v-model="item._checked" @change="handelCheckboxChange" />
						<view class="content-box">
							<view v-show="isManage" class="content-mask" @click.stop></view>
							<view class="hd">
								<!-- <view class="letter">Y</view> -->
								<view class="title line1">
									<text>{{item.account}}</text>
								</view>
								<view class="time">2019-03-03 12:01:01</view>
							</view>
							<view class="detail-box">
								<view class="detail-item">
									<view class="t-label">备注信息:</view>
									<view class="t-content">{{item.notes}}</view>
								</view>
							</view>
							<view class="bottom">
								<view class="status-box">
									<view class="status-item status-success">正常</view>
								</view>
								<view class="op-btns" v-show="!isManage">
									<!-- <view class="op-btn btn-success" @click="handelEdit(item)">编辑</view> -->
									<view class="op-btn btn-danger" @click="askDelete(item)">删除</view>
								</view>
							</view>
						</view>
					</view>
				</view>
			</template>
			<template v-else>
				<view class="empty-data">
					<u-empty text="数据为空" mode="data"></u-empty>
				</view>
			</template>
		</view>
		<view class="manage-box" v-show="isManage">
			<view class="wrap">
				<view class="delete-btn" @click="askDelete()">删除</view>
			</view>
		</view>
		<!-- 删除confirm -->
		<u-modal v-model="showConfirm" content="确认删除数据吗？" show-cancel-button @confirm="doDelete"></u-modal>
	</view>
</template>

<script>
	import IconCheckBox from '@/components/icon-checkbox'
	import _ from 'lodash'

	export default {
		components: {
			'icon-checkbox': IconCheckBox
		},
		props: {
			list: {
				type: Array,
				default: () => []
			},
			isManage: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				showConfirm: false,
				deleteItems: [],
			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			askDelete(row) {
				if (row) {
					this.deleteItems = []
					this.deleteItems.push(row)
				}
				this.showConfirm = true
			},
			async doDelete() {
				const ids = this.deleteItems.map(item => item.id)
				if (!ids.length) {
					this.$util.msg('未找到需要删除的数据')
					return
				}

				await this.$u.api.riskDelete({
					ids
				})
				const update_list = this.deleteByIds(ids)
				// 不重新加载页面，只更新list数据
				this.$emit('delete', update_list)
				this.$util.msg('删除成功')
			},
			deleteByIds(ids) {
				const copy_list = this.$u.deepClone(this.list)
				const new_list = _.filter(copy_list, (item) => {
					return !_.includes(ids, item.id)
				})
				return new_list
			},
			// item点击
			handelItemClick(row) {

			},
			// checkbox改变回调
			handelCheckboxChange() {
				this.deleteItems = _.filter(this.list, (item) => {
					return item._checked === true
				})
			},
			handelEdit(item) {
				this.$emit('edit', {
					...item
				})
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.list-box {
		display: flex;
		flex-direction: column;

		.list-item {
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;

			.wrap {
				position: relative;
				display: flex;
				align-items: center;
				gap: 20rpx;
				transition: all .15s;

				.content-box {
					flex: 1;
					display: flex;
					flex-direction: column;
					position: relative;

					.hd {
						display: flex;
						align-items: center;

						.letter {
							background-color: #2979ff;
							width: 40rpx;
							height: 40rpx;
							display: flex;
							align-items: center;
							justify-content: center;
							overflow: hidden;
							color: #fff;
							border-radius: 6rpx;
						}

						.title {
							flex: 1;
							font-weight: bolder;
						}

						.time {
							color: #82848a;
						}
					}

					.detail-box {
						margin-top: 20rpx;
						display: flex;
						flex-direction: column;
						gap: 6rpx;

						.detail-item {
							color: #82848a;
							display: flex;
							gap: 4rpx;

							.t-label {
								min-width: 120rpx;
							}
						}
					}

					.bottom {
						display: flex;
						justify-content: space-between;
						margin-top: 20rpx;

						.status-box {
							.status-item {}

							.status-success {
								color: #19be6b;
							}

							.status-stop {
								color: #fa3534;
							}
						}

						.op-btns {
							display: flex;
							gap: 20rpx;
							align-items: center;

							.op-btn {
								color: #909399;
								cursor: pointer;
								background-color: #909399;
								padding: 0 8rpx;
								border-radius: 6rpx;

								&:active {
									opacity: .8;
								}
							}

							.btn-success {
								background-color: #19be6b;
								color: #fff;
							}

							.btn-danger {
								background-color: #fa3534;
								color: #fff;
							}
						}
					}
				}

				.content-mask {
					position: absolute;
					left: 0;
					top: 0;
					width: 100%;
					height: 100%;
					z-index: 2;
					background-color: rgba(0, 0, 0, .4);
				}
			}
		}

		.list-item~.list-item {
			border-top: 1px solid #F5F5F5;
		}
	}

	.manage-box {
		position: fixed;
		bottom: 0;
		bottom: constant(safe-area-inset-bottom);
		bottom: env(safe-area-inset-bottom);
		z-index: 11;
		width: 100%;

		.wrap {
			.delete-btn {
				height: 100rpx;
				display: flex;
				gap: 20rpx;
				justify-content: center;
				align-items: center;
				color: #fff;
				background-color: #fa3534;
				cursor: pointer;

				&:active {
					opacity: .8;
				}
			}
		}
	}
</style>