<template>
	<view @touchmove.stop.prevent>
		<view style="padding: 30rpx;">
			<u-form :model="form" label-position="top">
				<u-form-item label="关键字类型" prop="keyword_type" :border-bottom="false">
					<button-checkbox :source="keywordTypeData" v-model="form.keyword_type" :showAll="false" />
				</u-form-item>
				<u-form-item label="关键字" prop="keyword" :border-bottom="false">
					<u-input v-model="form.keyword" />
				</u-form-item>
			</u-form>
		</view>
		<view class="btn-box">
			<u-button @click="reset">重 置</u-button>
			<u-button type="primary" @click="submit">确 定</u-button>
		</view>
	</view>
</template>

<script>
	import ButtonCheckbox from '@/components/manage-search/button-checkbox'

	export default {
		components: {
			ButtonCheckbox
		},
		props: {
			formData: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				form: {
					keyword: '',
					keyword_type: '',
				},
				keywordTypeData: [{
						label: '充值账号',
						value: 1
					},
					{
						label: '备注信息',
						value: 2
					},
				]
			}
		},
		watch: {
			formData: {
				handler(nv) {
					this.form = nv
				},
				immediate: true
			}
		},
		methods: {
			reset() {
				this.form = this.$options.data().form
			},
			submit() {
				this.$emit('filter', {
					...this.form
				})
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.btn-box {
		border-top: 1px solid #c8c9cc;
		display: flex;
		padding: 40rpx;
		gap: 20rpx;

		::v-deep {
			.u-btn {
				flex: 1;
			}
		}
	}
</style>