<template>
	<view class="search-result-box">
		<view class="result">搜索结果：共<text>{{total}}</text>条</view>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_search_content" :rebound="false"
			@scrolltolower="lower">
			<RiskList :list="list" @delete="handelDelete" @edit="handelEdit" />
			<u-loadmore :status="loading" v-show="list.length" icon-type="circle" @loadmore="fetchData"></u-loadmore>
		</scroll-view>
		<my-popup :show.sync="showEdit" :title="editTitle">
			<risk-edit :source="editForm" @submit="handelSave" />
		</my-popup>
	</view>
</template>

<script>
	import MyPopup from '@/components/manage-search/my-popup'
	import RiskEdit from './risk-edit'
	import RiskList from './risk-list'
	export default {
		components: {
			MyPopup,
			RiskList,
			RiskEdit
		},
		props: {
			keyword: {
				type: String,
				default: ''
			}
		},
		data() {
			return {
				queryForm: {
					keyword: '',
					keyword_type: '',
					page: 1,
					limit: 20,
				},
				list: [],
				total: 0,
				loading: 'loadmore',

				showEdit: false,
				editForm: {},
			}
		},
		computed: {
			editTitle() {
				if (this.editForm.id)
					return '编辑'
				else
					return `添加`
			},
		},
		watch: {
			keyword: {
				handler(nv) {
					this.queryForm.keyword = nv
				},
				immediate: true
			}
		},
		mounted() {
			this.fetchData()
		},
		methods: {
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
				} = await this.$u.api.riskList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 删除回调
			handelDelete(e) {
				this.reloadData()
			},
			// 编辑
			handelEdit(e) {
				this.editForm = e
				this.showEdit = true
			},
			// 添加、编辑时保存
			async handelSave(e) {
				await this.$u.api.riskCreate(e)
				this.$util.msg('保存成功')
				this.showEdit = false
				this.reloadData()
			},
		},
	}
</script>

<style scoped lang="scss" scoped>
	.search-result-box {

		.result {
			background-color: #f4f4f5;
			padding: 20rpx;
			color: #909399;

			&>text {
				color: red;
				font-weight: bolder;
				padding: 0 4rpx;
			}
		}

		.scroll_search_content {
			height: calc(62vh);
			height: calc(var(--vh) * 62);
		}
	}
</style>