<template>
	<view style="padding: 20rpx;" @touchmove.stop.prevent>
		<u-form :model="form" ref="uForm" :label-width="140">
			<u-form-item label="充值账号" prop="account">
				<u-input type="textarea" v-model="form.account" />
			</u-form-item>
			<u-form-item label="备注信息" prop="notes">
				<u-input type="textarea" v-model="form.notes" />
			</u-form-item>
		</u-form>
		<u-button type="primary" @click="submit">提交</u-button>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				form: {
					account: '',
					notes: '',
				},
				rules: {
					account: [{
						required: true,
						message: '请输入账号',
						// 可以单个或者同时写两个触发验证方式 
						trigger: ['change', 'blur'],
					}],
					notes: [{
						max: 255,
						message: '备注信息不能大于255个字',
						trigger: 'change'
					}]
				}
			}
		},
		watch: {
			source: {
				handler(nv) {
					this.form = nv
				},
				immediate: true
			}
		},
		mounted() {
			this.$refs.uForm.setRules(this.rules)
		},
		methods: {
			submit() {
				this.$refs.uForm.validate(valid => {
					if (valid) {
						console.log('验证通过')
						this.$emit('submit', {
							...this.form
						})
					} else {
						console.log('验证失败')
					}
				});
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
</style>